{"path":"/home/user/next-app/components/todo/TodoForm.tsx","content":"import React, { useState, FormEvent } from 'react';
import Input from '@/components/ui/input';
import { Button } from '@/components/ui/button';

interface TodoFormProps {
  onAdd: (text: string) => void;
}

const TodoForm: React.FC<TodoFormProps> = ({ onAdd }) => {
  const [text, setText] = useState('');

  const handleChange = (e: React.ChangeEvent<HTMLInputElement>) => {
    setText(e.target.value);
  };

  const handleSubmit = (e: FormEvent) => {
    e.preventDefault();
    if (text.trim()) {
      onAdd(text.trim());
      setText('');
    }
  };

  return (
    <form onSubmit={handleSubmit} className="flex items-center gap-2">
      <Input
        value={text}
        onChange={handleChange}
        placeholder="Add a new todo..."
        className="flex-1"
        autoFocus
      />
      <Button type="submit">Add</Button>
    </form>
  );
};

export default TodoForm;
"}

{"path":"/home/user/next-app/pages/index.tsx","content":"import React, { useState } from 'react';
import TodoForm from '@/components/todo/TodoForm';
import TodoList from '@/components/todo/TodoList';

export default function Home() {
  const [todos, setTodos] = useState<{ id: string; text: string }[]>([]);

  const handleAdd = (text: string) => {
    setTodos((prev) => [
      { id: Date.now().toString(), text },
      ...prev
    ]);
  };

  const handleDelete = (id: string) => {
    setTodos((prev) => prev.filter((todo) => todo.id !== id));
  };

  return (
    <div className="flex min-h-screen items-center justify-center bg-zinc-50 dark:bg-black">
      <main className="w-full max-w-md bg-white dark:bg-black rounded-xl shadow-lg p-8 flex flex-col items-center">
        <h1 className="text-3xl font-bold text-black dark:text-zinc-100 mb-6">Todo App</h1>
        <TodoForm onAdd={handleAdd} />
        <div className="mt-4 w-full">
          <TodoList todos={todos} onDelete={handleDelete} />
        </div>
      </main>
    </div>
  );
}
"}
